def wordBreak(s, wordDict):
    words = set(wordDict); memo = {}
    def dfs(s):
        if not s: return [[]]
        if s in memo: return memo[s]
        res = []
        for i in range(1, len(s)+1):
            if s[:i] in words:
                for subs in dfs(s[i:]): res.append([s[:i]] + subs)
        memo[s] = res; return res
    return [' '.join(x) for x in dfs(s)]

